+    it('should format memories correctly', async () => {
+      const { buildMem0SystemPrompt } = await import('../mem0-power');
+      const memories = [
+        { id: '1', memory: 'User prefers dark mode', score: 0.9 },
+        { id: '2', memory: 'User is working on a React project', score: 0.8 },
