+        results.push({
+          iteration: results.length + 1,
+          tool: tc.name,
+          arguments: tc.arguments,
+          result,
+        });
+        
+        // Add tool response to conversation
+        this.context.conversationHistory.push({
+          role: 'tool',
+          content: JSON.stringify(result),
+          toolCallId,
+          toolName: tc.name,
+        });
